{
    private readonly AppDbContext _db; // <-- SCOPED, now captive!
    public OrderCache(AppDbContext db) => _db = db;

    // _db was created during the FIRST request and is reused forever.
    // EF's change tracker accumulates entities across all requests,
    // the underlying connection may be disposed, and reads/writes
    // become non-thread-safe. Symptoms: 'A second operation started
    // on this context...', stale data, and ObjectDisposedException.
