// Spring: qualify one bean by name
interface Notifier { void send(String to, String msg); }

@Component("email") class EmailNotifier implements Notifier { /* ... */ }
@Component("sms")   class SmsNotifier   implements Notifier { /* ... */ }

@Service
class AlertService {
    private final Notifier notifier;
    AlertService(@Qualifier("sms") Notifier notifier) {  // pick one
        this.notifier = notifier;
    }
}

// Or inject ALL implementations as a collection
@Service
class Broadcaster {
    private final List<Notifier> notifiers;   // Spring injects every bean
    Broadcaster(List<Notifier> notifiers) { this.notifiers = notifiers; }
    void broadcast(String to, String msg) {
        notifiers.forEach(n -> n.send(to, msg));
    }
}

// .NET 8+: keyed services select one; collection injection gets all
