// ANTI-PATTERN: service locator hides the real dependencies
public class OrderService
{
    public void Place(Order o)
    {
        // Nothing in this class's public surface reveals these needs.
        var repo = ServiceLocator.Current.Get<IOrderRepository>();
        var gw   = ServiceLocator.Current.Get<IPaymentGateway>();
        gw.Charge(o.Total);
        repo.Save(o);
    }
