// Angular: hierarchical injector modifiers control the resolution walk
import { Injectable, Optional, Self, SkipSelf, Host, inject } from '@angular/core';

@Injectable()
export class WidgetService {
  // @Self      -> only look in THIS injector, do not walk up
  // @SkipSelf  -> skip this injector, start at the parent
  // @Host      -> stop the upward walk at the host component
  // @Optional  -> return null instead of throwing if not found
  private logger = inject(LoggerService, { optional: true, skipSelf: true });
}

// Angular resolves a token by walking element injectors up to the
// root (module/environment) injector; the FIRST provider found wins,
// which is how a component can override a service just for its subtree.

public interface PaymentGateway { PaymentResult charge(Money amount); }

@Component("stripe")
class StripeGateway implements PaymentGateway {
    public PaymentResult charge(Money amount) { /* call Stripe */ return PaymentResult.ok(); }
}

@Component("paypal")
class PaypalGateway implements PaymentGateway {
    public PaymentResult charge(Money amount) { /* call PayPal */ return PaymentResult.ok(); }
}

public interface OrderRepository { void save(Order o); }

@Service
class OrderService {
    private final PaymentGateway gateway;
    private final OrderRepository repository;

    // constructor injection; @Qualifier disambiguates the two gateways
    OrderService(@Qualifier("stripe") PaymentGateway gateway,
                 OrderRepository repository) {
        this.gateway = gateway;
        this.repository = repository;
    }

    public void placeOrder(Order order) {
        PaymentResult result = gateway.charge(order.total());
        if (result.isSuccessful()) {
            repository.save(order);
        } else {
            throw new PaymentDeclinedException(order.id());
        }
    }
}

import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class OrderServiceTest {

    @Test
    void savesOrder_whenPaymentSucceeds() {
        // Arrange: fakes injected via the constructor, no Spring context
        PaymentGateway gateway = mock(PaymentGateway.class);
        OrderRepository repository = mock(OrderRepository.class);
        when(gateway.charge(any())).thenReturn(PaymentResult.ok());

        OrderService service = new OrderService(gateway, repository);
        Order order = new Order("A-1", Money.usd(4200));

        // Act
        service.placeOrder(order);

        // Assert: repository was asked to persist exactly once
        verify(repository, times(1)).save(order);
    }

    @Test
    void doesNotSave_whenPaymentDeclined() {
        PaymentGateway gateway = mock(PaymentGateway.class);
        OrderRepository repository = mock(OrderRepository.class);
        when(gateway.charge(any())).thenReturn(PaymentResult.declined());

        OrderService service = new OrderService(gateway, repository);

        assertThrows(PaymentDeclinedException.class,
            () -> service.placeOrder(new Order("A-2", Money.usd(999))));
        verify(repository, never()).save(any());   // no persistence on failure
    }
}

