using Xunit;

public class ReportGeneratorTests
{
    [Fact]
    public void Generate_SendsExactlyOneEmail()
    {
        var repo = new Mock<IReportRepository>();
        var sender = new Mock<IEmailSender>();
        repo.Setup(r => r.LoadFor(42))
            .Returns(new ReportData { Name = "Ada", Email = "ada@x.io" });

        var sut = new ReportGenerator(repo.Object, sender.Object);

        sut.Generate(42);

        sender.Verify(s => s.Send("ada@x.io", "Your report", "Report for Ada"),
                      Times.Once());
    }
